{
  "name": "Purchase Orders",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "PurchaseOrders",
      "entity": {
        "name": "PurchaseOrder",
        "collection": "purchase_orders",
        "fields": [
          {
            "name": "id",
            "type": "string",
            "primaryKey": true
          },
          {
            "name": "poNumber",
            "type": "string",
            "required": true
          },
          {
            "name": "supplierId",
            "type": "string",
            "required": true
          },
          {
            "name": "items",
            "type": "array"
          },
          {
            "name": "totalAmount",
            "type": "number"
          },
          {
            "name": "status",
            "type": "enum",
            "enum": [
              "draft",
              "submitted",
              "approved",
              "received",
              "cancelled"
            ]
          },
          {
            "name": "expectedDelivery",
            "type": "date"
          },
          {
            "name": "receivedAt",
            "type": "date"
          }
        ]
      },
      "traits": [
        {
          "name": "PurchaseOrderInteraction",
          "category": "interaction",
          "linkedEntity": "PurchaseOrder",
          "stateMachine": {
            "states": [
              {
                "name": "draft",
                "isInitial": true
              },
              {
                "name": "submitted",
                "isInitial": false
              },
              {
                "name": "approved",
                "isInitial": false
              },
              {
                "name": "received",
                "isInitial": false
              },
              {
                "name": "cancelled",
                "isInitial": false
              }
            ],
            "events": [
              {
                "key": "SUBMIT",
                "name": "Submit"
              },
              {
                "key": "APPROVE",
                "name": "Approve"
              },
              {
                "key": "RECEIVE",
                "name": "Receive"
              },
              {
                "key": "CANCEL",
                "name": "Cancel"
              }
            ],
            "transitions": [
              {
                "from": "draft",
                "to": "submitted",
                "event": "SUBMIT",
                "effects": [
                  [
                    "set",
                    "status",
                    "submitted"
                  ]
                ]
              },
              {
                "from": "submitted",
                "to": "approved",
                "event": "APPROVE",
                "effects": [
                  [
                    "set",
                    "status",
                    "approved"
                  ]
                ]
              },
              {
                "from": "approved",
                "to": "received",
                "event": "RECEIVE",
                "effects": [
                  [
                    "set",
                    "status",
                    "received"
                  ],
                  [
                    "set",
                    "receivedAt",
                    "@now"
                  ]
                ]
              },
              {
                "from": [
                  "draft",
                  "submitted"
                ],
                "to": "cancelled",
                "event": "CANCEL",
                "effects": [
                  [
                    "set",
                    "status",
                    "cancelled"
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "PurchaseOrderPage",
          "path": "/purchase_orders",
          "entity": "PurchaseOrder",
          "traits": [
            "PurchaseOrderInteraction"
          ]
        }
      ]
    }
  ]
}

