{
  "name": "SLA Tracking",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "SLATracking",
      "entity": {
        "name": "SLA",
        "collection": "slas",
        "fields": [
          {
            "name": "id",
            "type": "string",
            "primaryKey": true
          },
          {
            "name": "ticketId",
            "type": "string",
            "required": true
          },
          {
            "name": "priority",
            "type": "enum",
            "enum": [
              "low",
              "medium",
              "high",
              "critical"
            ]
          },
          {
            "name": "responseDeadline",
            "type": "timestamp"
          },
          {
            "name": "resolutionDeadline",
            "type": "timestamp"
          },
          {
            "name": "respondedAt",
            "type": "timestamp"
          },
          {
            "name": "resolvedAt",
            "type": "timestamp"
          },
          {
            "name": "status",
            "type": "enum",
            "enum": [
              "pending",
              "responded",
              "breached",
              "met"
            ]
          }
        ]
      },
      "traits": [
        {
          "name": "SLAInteraction",
          "category": "interaction",
          "linkedEntity": "SLA",
          "stateMachine": {
            "states": [
              {
                "name": "pending",
                "isInitial": true
              },
              {
                "name": "responded",
                "isInitial": false
              },
              {
                "name": "breached",
                "isInitial": false
              },
              {
                "name": "met",
                "isInitial": false
              }
            ],
            "events": [
              {
                "key": "RESPOND",
                "name": "First Response"
              },
              {
                "key": "RESOLVE",
                "name": "Resolve"
              },
              {
                "key": "BREACH",
                "name": "SLA Breached"
              }
            ],
            "transitions": [
              {
                "from": "pending",
                "to": "responded",
                "event": "RESPOND",
                "effects": [
                  [
                    "set",
                    "respondedAt",
                    "@now"
                  ],
                  [
                    "set",
                    "status",
                    "responded"
                  ]
                ]
              },
              {
                "from": "responded",
                "to": "met",
                "event": "RESOLVE",
                "effects": [
                  [
                    "set",
                    "resolvedAt",
                    "@now"
                  ],
                  [
                    "set",
                    "status",
                    "met"
                  ]
                ]
              },
              {
                "from": [
                  "pending",
                  "responded"
                ],
                "to": "breached",
                "event": "BREACH",
                "effects": [
                  [
                    "set",
                    "status",
                    "breached"
                  ],
                  [
                    "notify",
                    "error",
                    "SLA Breached!"
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "SLAPage",
          "path": "/slas",
          "entity": "SLA",
          "traits": [
            "SLAInteraction"
          ]
        }
      ]
    }
  ]
}

