{
  "name": "Invoice Management",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "InvoiceManagement",
      "entity": {
        "name": "Invoice",
        "collection": "invoices",
        "fields": [
          {
            "name": "id",
            "type": "string",
            "primaryKey": true
          },
          {
            "name": "invoiceNumber",
            "type": "string",
            "required": true
          },
          {
            "name": "customerId",
            "type": "string",
            "required": true
          },
          {
            "name": "items",
            "type": "array"
          },
          {
            "name": "subtotal",
            "type": "number"
          },
          {
            "name": "tax",
            "type": "number"
          },
          {
            "name": "total",
            "type": "number",
            "required": true
          },
          {
            "name": "status",
            "type": "enum",
            "enum": [
              "draft",
              "sent",
              "paid",
              "overdue",
              "cancelled"
            ]
          },
          {
            "name": "dueDate",
            "type": "date"
          },
          {
            "name": "paidAt",
            "type": "date"
          },
          {
            "name": "createdAt",
            "type": "date"
          }
        ]
      },
      "traits": [
        {
          "name": "InvoiceInteraction",
          "category": "interaction",
          "linkedEntity": "Invoice",
          "stateMachine": {
            "states": [
              {
                "name": "draft",
                "isInitial": true
              },
              {
                "name": "sent",
                "isInitial": false
              },
              {
                "name": "paid",
                "isInitial": false
              },
              {
                "name": "overdue",
                "isInitial": false
              },
              {
                "name": "cancelled",
                "isInitial": false
              }
            ],
            "events": [
              {
                "key": "SEND",
                "name": "Send Invoice"
              },
              {
                "key": "MARK_PAID",
                "name": "Mark Paid"
              },
              {
                "key": "MARK_OVERDUE",
                "name": "Mark Overdue"
              },
              {
                "key": "CANCEL",
                "name": "Cancel"
              }
            ],
            "transitions": [
              {
                "from": "draft",
                "to": "sent",
                "event": "SEND",
                "effects": [
                  [
                    "set",
                    "status",
                    "sent"
                  ],
                  [
                    "call-service",
                    "email",
                    "send",
                    {
                      "to": "@entity.customerId",
                      "subject": "Invoice @entity.invoiceNumber",
                      "body": "Please find attached invoice"
                    },
                    {
                      "onSuccess": "EMAIL_SENT",
                      "onError": "EMAIL_FAILED"
                    }
                  ]
                ]
              },
              {
                "from": "sent",
                "to": "paid",
                "event": "MARK_PAID",
                "effects": [
                  [
                    "set",
                    "status",
                    "paid"
                  ],
                  [
                    "set",
                    "paidAt",
                    "@now"
                  ]
                ]
              },
              {
                "from": "sent",
                "to": "overdue",
                "event": "MARK_OVERDUE",
                "effects": [
                  [
                    "set",
                    "status",
                    "overdue"
                  ]
                ]
              },
              {
                "from": [
                  "draft",
                  "sent"
                ],
                "to": "cancelled",
                "event": "CANCEL",
                "effects": [
                  [
                    "set",
                    "status",
                    "cancelled"
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "InvoicePage",
          "path": "/invoices",
          "entity": "Invoice",
          "traits": [
            "InvoiceInteraction"
          ]
        }
      ]
    }
  ]
}

